import asyncio

from seed import AsyncSeedApi, TypesObjectWithRequiredField

client = AsyncSeedApi(
    token="YOUR_TOKEN",
    base_url="https://yourhost.com/path/to/api",
)


async def main() -> None:
    await client.endpoints_container.endpoints_container_get_and_return_map_of_prim_to_object(
        request={
            "key": TypesObjectWithRequiredField(
                string="string",
            )
        },
    )


asyncio.run(main())

